parameters.jsCode:
const input = $json || {};

function cleanText(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function asBool(value) {
  return value === true || value === 1 || value === "1" || value === "true";
}

const inputEvent = asObject(input.input_event);
const customerContext = asObject(input.customer_context);
const caseContext = asObject(input.case_context);
const conversationContext = asObject(input.conversation_context);
const businessContext = asObject(input.business_context);
const serviceContext = asObject(
  input.service_context ||
  businessContext.service_context ||
  {}
);

const normalized = {
  input_event: {
    ...inputEvent,

    event_type: cleanText(inputEvent.event_type || "whatsapp_message"),
    channel: cleanText(inputEvent.channel || "whatsapp"),

    wa_id: cleanText(
      inputEvent.wa_id ||
      inputEvent.phone_normalized ||
      input.wa_id ||
      input.phone_normalized
    ),

    phone_normalized: cleanText(
      inputEvent.phone_normalized ||
      inputEvent.wa_id ||
      input.phone_normalized ||
      input.wa_id
    ),

    provider_message_id: cleanText(
      inputEvent.provider_message_id ||
      inputEvent.message_id ||
      inputEvent.id ||
      input.provider_message_id ||
      input.message_id
    ),

    context_message_id: cleanText(
      inputEvent.context_message_id ||
      input.context_message_id
    ),

    phone_number_id: cleanText(
      inputEvent.phone_number_id ||
      input.phone_number_id
    ),

    contact_name: cleanText(
      inputEvent.contact_name ||
      input.contact_name ||
      customerContext.full_name ||
      customerContext.name
    ),

    message_text: cleanText(
      inputEvent.message_text ||
      inputEvent.text ||
      input.message?.text ||
      input.message_text ||
      input.text
    ),

    message_type: cleanText(
      inputEvent.message_type ||
      input.message_type ||
      "text"
    ),

    received_at: cleanText(
      inputEvent.received_at ||
      input.received_at
    ),

    timestamp: cleanText(
      inputEvent.timestamp ||
      input.timestamp
    )
  },

  customer_context: {
    ...customerContext,
    customer_id: customerContext.customer_id ?? customerContext.id_customer ?? null,
    id_customer: customerContext.id_customer ?? customerContext.customer_id ?? null,
    full_name: cleanText(customerContext.full_name || customerContext.name),
    lifecycle_stage: cleanText(customerContext.lifecycle_stage || "unknown"),
    cluster: cleanText(customerContext.cluster || "unknown"),
    total_orders: Number(customerContext.total_orders || 0),
    total_revenue: Number(customerContext.total_revenue || 0),
    last_order_at: cleanText(customerContext.last_order_at)
  },

  case_context: {
    ...caseContext,
    case_id: caseContext.case_id ?? caseContext.id ?? null,
    status: cleanText(caseContext.status || "none"),
    department: cleanText(caseContext.department || "unknown"),
    service_code: cleanText(caseContext.service_code || "unknown"),
    case_origin_type: cleanText(caseContext.case_origin_type || ""),
    case_type: cleanText(caseContext.case_type || "unknown"),
    priority: cleanText(caseContext.priority || "normal")
  },

  conversation_context: {
    ...conversationContext,
    last_messages: asArray(conversationContext.last_messages)
      .slice(-10)
      .map((m) => ({
        direction: cleanText(m.direction),
        message_text: cleanText(m.message_text),
        created_at: cleanText(m.created_at)
      }))
  },

  business_context: {
    ...businessContext,
    has_open_complaint: asBool(businessContext.has_open_complaint),
    has_open_quote: asBool(businessContext.has_open_quote),
    recent_campaigns: asArray(businessContext.recent_campaigns),
    recent_orders: asArray(businessContext.recent_orders),
    service_context: serviceContext,
    risk_flags: asArray(businessContext.risk_flags || input.risk_flags)
  },

  service_context: {
    ...serviceContext,
    has_service_context: asBool(serviceContext.has_service_context),
    dominant_service: cleanText(
      serviceContext.dominant_service ||
      serviceContext.service_code ||
      input.service_code
    ),
    service_code: cleanText(
      serviceContext.service_code ||
      serviceContext.dominant_service ||
      input.service_code
    ),
    source_table: serviceContext.source_table ?? null,
    source_id: serviceContext.source_id ?? null,
    id_order: serviceContext.id_order ?? null,
    id_customer: serviceContext.id_customer ?? null,
    invoice_number: serviceContext.invoice_number ?? null,
    case_origin_type: cleanText(serviceContext.case_origin_type || "")
  },

  risk_flags: asArray(input.risk_flags || businessContext.risk_flags),
  resolver_meta: asObject(input.resolver_meta),

  raw_input: input
};

if (!normalized.input_event.wa_id) {
  normalized._validation_error = "Missing wa_id";
}

if (!normalized.input_event.message_text && normalized.input_event.message_type === "text") {
  normalized._validation_error = "Missing message_text";
}

return [{ json: normalized }];

const data = $json || {};

const allowedIntents = [
  "greeting",
  "quote_request",
  "purchase_advice",
  "product_availability",
  "shipping_question",
  "order_status",
  "complaint",
  "warranty",
  "return_or_exchange",
  "postventa_armado",
  "postventa_mantencion",
  "postventa_general",
  "campaign_response",
  "review_response",
  "human_request",
  "thanks_or_closure",
  "customer_rejection",
  "opt_out",
  "spam_or_irrelevant",
  "unknown"
];

const allowedAgents = [
  "AI_AGENT_Quote",
  "AI_AGENT_Sales",
  "AI_AGENT_SAC",
  "AI_AGENT_Postventa",
  "AI_AGENT_Campaign",
  "AI_AGENT_Knowledge",
  "AI_AGENT_GENERAL",
  "executor",
  "OPS_Handoff_Manager",
  "OPS_Case_Closer",
  "OPS_Tool_Request",
  "noop",
  "quote_agent",
  "sales_agent",
  "sac_agent",
  "postventa_agent",
  "campaign_agent",
  "knowledge_agent",
  "general_agent",
  "human_review"
];

const allowedRisk = ["low", "medium", "high"];

function clean(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function normalizeText(value) {
  return clean(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[¿?¡!.,;:()[\]{}"']/g, "")
    .replace(/\s+/g, " ");
}

function asObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function asBool(value, fallback = false) {
  if (value === true || value === 1 || value === "1" || value === "true") return true;
  if (value === false || value === 0 || value === "0" || value === "false") return false;
  return fallback;
}

function clamp01(value, fallback = 0.8) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(0, Math.min(1, n));
}

function includesAny(text, terms) {
  const t = normalizeText(text);
  return terms.some(term => t.includes(normalizeText(term)));
}

function pickFirst(...values) {
  for (const value of values) {
    const v = clean(value);
    if (v) return v;
  }
  return "";
}

function pickFirstNumber(...values) {
  for (const value of values) {
    if (value === null || value === undefined || value === "") continue;
    const n = Number(value);
    if (Number.isFinite(n) && n > 0) return n;
  }
  return null;
}

function normalizeTargetAgent(value) {
  const v = String(value || "").trim();

  const map = {
    quote_agent: "AI_AGENT_Quote",
    sales_agent: "AI_AGENT_Sales",
    sac_agent: "AI_AGENT_SAC",
    postventa_agent: "AI_AGENT_Postventa",
    campaign_agent: "AI_AGENT_Campaign",
    knowledge_agent: "AI_AGENT_Knowledge",
    general_agent: "AI_AGENT_SAC",
    human_review: "OPS_Handoff_Manager",
    AI_AGENT_Quote: "AI_AGENT_Quote",
    AI_AGENT_Sales: "AI_AGENT_Sales",
    AI_AGENT_SAC: "AI_AGENT_SAC",
    AI_AGENT_Postventa: "AI_AGENT_Postventa",
    AI_AGENT_Campaign: "AI_AGENT_Campaign",
    AI_AGENT_Knowledge: "AI_AGENT_Knowledge",
    AI_AGENT_GENERAL: "AI_AGENT_SAC",
    OPS_Handoff_Manager: "OPS_Handoff_Manager",
    OPS_Case_Closer: "OPS_Case_Closer",
    OPS_Tool_Request: "OPS_Tool_Request",
    executor: "executor",
    noop: "noop"
  };

  return map[v] || "AI_AGENT_SAC";
}

function normalizeIntent(value) {
  const v = normalizeText(value);

  const map = {
    greeting: "greeting",
    saludo: "greeting",
    quote_request: "quote_request",
    cotizacion: "quote_request",
    cotizar: "quote_request",
    purchase_advice: "purchase_advice",
    product_availability: "product_availability",
    shipping_question: "shipping_question",
    order_status: "order_status",
    complaint: "complaint",
    reclamo: "complaint",
    warranty: "warranty",
    garantia: "warranty",
    return_or_exchange: "return_or_exchange",
    devolucion: "return_or_exchange",
    postventa_armado: "postventa_armado",
    armado: "postventa_armado",
    postventa_mantencion: "postventa_mantencion",
    mantencion: "postventa_mantencion",
    mantenimiento: "postventa_mantencion",
    postventa_general: "postventa_general",
    campaign_response: "campaign_response",
    review_response: "review_response",
    human_request: "human_request",
    thanks_or_closure: "thanks_or_closure",
    customer_rejection: "customer_rejection",
    opt_out: "opt_out",
    spam_or_irrelevant: "spam_or_irrelevant",
    unknown: "unknown"
  };

  return map[v] || "unknown";
}

function normalizeRisk(value) {
  const v = normalizeText(value);
  if (["low", "bajo"].includes(v)) return "low";
  if (["medium", "medio", "moderate"].includes(v)) return "medium";
  if (["high", "alto"].includes(v)) return "high";
  return "medium";
}

function normalizeService(value) {
  const v = normalizeText(value);

  if (!v) return "unknown";
  if (["postventa_armado", "armado"].includes(v)) return "postventa_armado";
  if (["postventa_mantencion", "mantencion", "mantenimiento"].includes(v)) return "postventa_mantencion";
  if (v.includes("postventa")) return "postventa_general";
  if (["campaign", "campana", "campaña", "campaign_response"].includes(v)) return "campaign";
  if (["knowledge", "faq", "documentacion", "documentación"].includes(v)) return "knowledge";
  if (["garantia", "reclamo", "devolucion", "warranty", "complaint", "sac"].includes(v)) return "sac";
  if (["quote", "cotizacion", "cotización"].includes(v)) return "quote";
  if (["sales", "ventas", "asesoria_compra", "purchase_advice", "product_availability"].includes(v)) return "sales";
  return v;
}

function mapServiceToAgent(service) {
  const normalized = normalizeService(service);

  if (["postventa_armado", "postventa_mantencion", "postventa_general"].includes(normalized)) return "AI_AGENT_Postventa";
  if (normalized === "campaign") return "AI_AGENT_Campaign";
  if (normalized === "knowledge") return "AI_AGENT_Knowledge";
  if (normalized === "quote") return "AI_AGENT_Quote";
  if (normalized === "sales") return "AI_AGENT_Sales";
  if (normalized === "sac") return "AI_AGENT_SAC";
  return null;
}

function buildSwitchAction({
  route = false,
  execute = false,
  handoff = false,
  close = false,
  noop = false,
  suppressMail = true,
  suppressHandoff = true,
  blockedReason = null
}) {
  return {
    should_route_to_agent: route,
    should_execute_response: execute,
    should_handoff: handoff,
    should_close_case: close,
    should_noop: noop,
    should_suppress_mail: suppressMail,
    should_suppress_handoff: suppressHandoff,
    blocked_reason: blockedReason
  };
}

const rawInput = asObject(data.raw_input);
const inputEvent = asObject(data.input_event || rawInput.input_event);
const customerContext = asObject(data.customer_context || rawInput.customer_context);
const caseContext = asObject(data.case_context || rawInput.case_context);
const conversationContext = asObject(data.conversation_context || rawInput.conversation_context);
const businessContext = asObject(data.business_context || rawInput.business_context);
const serviceContext = asObject(data.service_context || rawInput.service_context);
const resolverMeta = asObject(data.resolver_meta || rawInput.resolver_meta);

const parsedIntent = normalizeIntent(
  pickFirst(
    data.classification?.intent,
    data.intent
  )
);

const parsedTargetAgent = normalizeTargetAgent(
  pickFirst(
    data.classification?.target_agent,
    data.routing?.target_agent,
    data.routing?.next_workflow,
    data.target_agent
  )
);

let riskLevel = normalizeRisk(
  pickFirst(
    data.classification?.risk_level,
    data.risk_level,
    "medium"
  )
);

let confidence = clamp01(
  data.classification?.confidence ?? data.confidence,
  0.82
);

const currentText = normalizeText(
  inputEvent.message_text ||
  inputEvent.text ||
  businessContext.current_message_flags?.current_message_text
);

const dominantService = normalizeService(
  pickFirst(
    serviceContext.dominant_service,
    serviceContext.service_code,
    caseContext.service_code,
    data.case_decision?.service_code
  )
);

const dominantContextAgent = mapServiceToAgent(dominantService);

const messageType = normalizeText(inputEvent.message_type || "text");
const isButtonOrInteractive =
  messageType === "button" ||
  messageType === "interactive" ||
  messageType === "list_reply";

const greetingTerms = [
  "hola",
  "holaa",
  "hola hola",
  "buenas",
  "buena",
  "buen dia",
  "buenos dias",
  "buenas tardes",
  "buenas noches"
];

const weakContinuationTerms = [
  "si",
  "sí",
  "ok",
  "oka",
  "oki",
  "dale",
  "me interesa",
  "perfecto",
  "quiero",
  "lo quiero",
  "me sirve",
  "listo"
];

const declineTerms = [
  "no gracias",
  "no, gracias",
  "no me interesa",
  "paso",
  "por ahora no",
  "no quiero"
];

const legalTerms = [
  "sernac",
  "demanda",
  "abogado",
  "legal",
  "denuncia",
  "estafa",
  "funa",
  "accidente",
  "lesion",
  "lesión"
];

const humanTerms = [
  "quiero hablar con una persona",
  "quiero hablar con alguien",
  "quiero hablar con humano",
  "necesito hablar con alguien",
  "necesito hablar con una persona",
  "ejecutivo",
  "supervisor",
  "operador"
];

const complaintTerms = [
  "reclamo",
  "garantia",
  "garantía",
  "devolucion",
  "devolución",
  "reembolso",
  "dañado",
  "danado",
  "roto",
  "mala experiencia"
];

const quoteTerms = [
  "cotizar",
  "cotizacion",
  "cotización",
  "presupuesto",
  "valor"
];

const commercialTerms = [
  "catalogo",
  "catálogo",
  "stock",
  "precio",
  "disponibilidad",
  "producto",
  "productos",
  "comprar",
  "maquina",
  "máquina",
  "banca",
  "rack",
  "barra",
  "disco",
  "mancuerna",
  "mancuernas"
];

const isGreetingOnly = greetingTerms.includes(currentText);
const isWeakContinuation = weakContinuationTerms.includes(currentText) || isButtonOrInteractive || isGreetingOnly;
const isExplicitDecline = declineTerms.includes(currentText);
const isLegalRisk = includesAny(currentText, legalTerms);
const isHumanRequest = includesAny(currentText, humanTerms);
const isComplaint = includesAny(currentText, complaintTerms);
const isQuoteIntent = includesAny(currentText, quoteTerms);
const isCommercialIntent = includesAny(currentText, commercialTerms);

const conversationCaseId = pickFirstNumber(
  caseContext.conversation_case_id,
  caseContext.case_id
);

const hasActiveCase =
  !!conversationCaseId &&
  !["closed", "archived", "resolved"].includes(normalizeText(caseContext.status)) &&
  !["closed", "archived"].includes(normalizeText(caseContext.lifecycle_status));

const manualLockActive =
  asBool(resolverMeta.manual_lock_active, false) ||
  asBool(caseContext.manual_lock_active, false);

const operatorActive =
  asBool(resolverMeta.operator_active, false) ||
  asBool(caseContext.operator_active, false);

const botCanContinue =
  resolverMeta.bot_can_continue !== false &&
  resolverMeta.bot_can_continue !== "false";

const recommendedBotMode = normalizeText(resolverMeta.recommended_bot_mode);

let intent = parsedIntent;
let targetAgent = parsedTargetAgent;
let actionType = "route_to_agent";
let blockedReason = null;
let decisionReason = "model_routing";
let requiresHuman = false;
let allowedToAutoReply = false;

if (!botCanContinue || manualLockActive || operatorActive || recommendedBotMode === "operator_locked") {
  intent = parsedIntent === "unknown" ? "unknown" : parsedIntent;
  targetAgent = "noop";
  actionType = "no_action";
  requiresHuman = true;
  blockedReason = "operator_or_manual_lock_active";
  decisionReason = "operational_lock";
}

else if (["postventa_armado", "postventa_mantencion", "postventa_general"].includes(dominantService)) {
  if (isExplicitDecline && hasActiveCase) {
    intent = "customer_rejection";
    targetAgent = "OPS_Case_Closer";
    actionType = "close_candidate";
    riskLevel = "low";
    confidence = Math.max(confidence, 0.9);
    decisionReason = "postventa_customer_rejection";
  } else {
    intent =
      dominantService === "postventa_armado"
        ? "postventa_armado"
        : dominantService === "postventa_mantencion"
          ? "postventa_mantencion"
          : "postventa_general";
    targetAgent = "AI_AGENT_Postventa";
    actionType = "route_to_agent";
    riskLevel = riskLevel === "high" ? "high" : "medium";
    confidence = Math.max(confidence, 0.86);
    decisionReason = isWeakContinuation
      ? "postventa_continuity"
      : "postventa_domain_priority";
  }
}

else if (dominantContextAgent && isWeakContinuation) {
  targetAgent = dominantContextAgent;
  actionType = "route_to_agent";
  confidence = Math.max(confidence, 0.84);
  decisionReason = "contextual_continuity";

  if (dominantContextAgent === "AI_AGENT_Quote") intent = "quote_request";
  if (dominantContextAgent === "AI_AGENT_Sales" && intent === "unknown") intent = "purchase_advice";
  if (dominantContextAgent === "AI_AGENT_SAC" && intent === "unknown") intent = "complaint";
  if (dominantContextAgent === "AI_AGENT_Campaign" && intent === "unknown") intent = "campaign_response";
}

else if (isLegalRisk || isHumanRequest || isComplaint || recommendedBotMode === "sac_conversational") {
  targetAgent = "AI_AGENT_SAC";
  actionType = "route_to_agent";
  intent =
    isHumanRequest
      ? "human_request"
      : isComplaint
        ? "complaint"
        : parsedIntent === "unknown"
          ? "complaint"
          : parsedIntent;
  riskLevel = isLegalRisk ? "high" : "medium";
  confidence = Math.max(confidence, 0.86);
  decisionReason = isLegalRisk ? "legal_or_sensitive_request" : "sac_context_or_request";
}

else if (isQuoteIntent) {
  targetAgent = "AI_AGENT_Quote";
  actionType = "route_to_agent";
  intent = "quote_request";
  riskLevel = "low";
  confidence = Math.max(confidence, 0.84);
  decisionReason = "explicit_quote_request";
}

else if (isCommercialIntent) {
  targetAgent = "AI_AGENT_Sales";
  actionType = "route_to_agent";
  intent = parsedIntent === "unknown" ? "purchase_advice" : parsedIntent;
  riskLevel = "low";
  confidence = Math.max(confidence, 0.82);
  decisionReason = "commercial_request";
}

else if (!allowedAgents.includes(targetAgent)) {
  targetAgent = dominantContextAgent || "AI_AGENT_SAC";
  actionType = "route_to_agent";
  intent = intent === "unknown" && targetAgent === "AI_AGENT_SAC" ? "unknown" : intent;
  decisionReason = "normalized_invalid_target";
}

if (!allowedIntents.includes(intent)) {
  intent = "unknown";
}

if (!allowedRisk.includes(riskLevel)) {
  riskLevel = "medium";
}

let nextWorkflow = null;
let finalAction = null;
let switchAction = null;

if (actionType === "no_action") {
  nextWorkflow = null;
  finalAction = "no_action";
  switchAction = buildSwitchAction({
    route: false,
    execute: false,
    handoff: false,
    close: false,
    noop: true,
    suppressMail: true,
    suppressHandoff: true,
    blockedReason
  });
}

if (actionType === "close_candidate") {
  nextWorkflow = "OPS_Case_Closer";
  finalAction = "close_candidate";
  switchAction = buildSwitchAction({
    route: false,
    execute: false,
    handoff: false,
    close: true,
    noop: false,
    suppressMail: true,
    suppressHandoff: true,
    blockedReason
  });
}

if (actionType === "route_to_agent") {
  nextWorkflow = targetAgent;
  finalAction = "route_to_agent";
  switchAction = buildSwitchAction({
    route: true,
    execute: false,
    handoff: false,
    close: false,
    noop: false,
    suppressMail: true,
    suppressHandoff: true,
    blockedReason
  });
}

if (targetAgent === "OPS_Handoff_Manager") {
  actionType = "handoff_to_human";
  requiresHuman = true;
  nextWorkflow = "OPS_Handoff_Manager";
  finalAction = "handoff_to_human";
  switchAction = buildSwitchAction({
    route: false,
    execute: false,
    handoff: true,
    close: false,
    noop: false,
    suppressMail: false,
    suppressHandoff: false,
    blockedReason
  });
}

const department = pickFirst(
  data.case_decision?.department,
  data.case_update?.department,
  caseContext.department,
  dominantContextAgent === "AI_AGENT_Postventa" ? "Postventa" : "",
  dominantContextAgent === "AI_AGENT_Sales" || targetAgent === "AI_AGENT_Quote" ? "Ventas" : "",
  "SAC"
);

const serviceCode = pickFirst(
  data.case_decision?.service_code,
  data.case_update?.service_code,
  serviceContext.service_code,
  serviceContext.dominant_service,
  caseContext.service_code,
  dominantService === "unknown" ? "organic_whatsapp" : dominantService
);

const caseOriginType = pickFirst(
